sql:
SELECT DISTINCT player_name
FROM game_batting_stats
WHERE runs >= 1;

SELECT player_name
FROM game_batting_stats
WHERE rbis = (SELECT MAX(rbis) FROM game_batting_stats);

SELECT MAX(jersey_number) AS max_jersey
FROM team_rosters
WHERE team_id = 1;

external_knowledge:
- A team is considered to have 'Improved' if its win percentage and run difference have increased from the previous season; 
- A team is considered to have 'Declined' if its win percentage and run difference have decreased from the previous season;
- A team is considered 'Stable/Varied' if its win percentage and run difference have changed in different directions or remained the same from the previous season.

sql:
SELECT position, COUNT(*) AS player_count, AVG(jersey_number) AS average_jersey_number
FROM team_rosters
GROUP BY position;
